/* SmsRsvSendMapper.updateSmsRsvInfo */
UPDATE  MSG_SMS_LIST
SET       RESULT_YN = #{resultYn}
		, RESULT_CODE = #{resultCode}
WHERE   MSG_NO = #{msgNo}

/* SmsRsvSendMapper.updateSmsRsvErrInfo */
UPDATE  MSG_SMS_LIST
SET       RESULT_YN = #{resultYn}
		, RESULT_CODE = #{resultCode}
WHERE   TO_DATE(REQUEST_TIME, 'YYYYMMDDHH24MISS') = TRUNC(SYSDATE, 'HH24')
AND		MSG_USG_YN = 'Y'
AND		RESULT_YN = 'N'
